{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { size: A4 landscape; margin: 10mm 12mm 8mm 12mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 9pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 100%; margin: 0; padding: 0; }

  /* HEADER */
  .hotel-logo { max-height: 52px; max-width: 95px; }
  .logo-box { display: inline-block; width: 44px; height: 44px; background: #1a1a2e; color: #fff; font-size: 15pt; font-weight: 700; text-align: center; line-height: 44px; border-radius: 5px; }
  .hotel-name { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 12pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 12px 0 14px; }

  /* PILLS */
  .pill { display: inline-block; padding: 2px 9px; border-radius: 10px; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; margin-right: 5px; border: 1px solid #d1d5db; background: #f9fafb; color: #374151; }
  .pills-row { margin-bottom: 12px; }

  /* SECTION TITLE */
  .section-title { font-size: 7.5pt; font-weight: 700; color: #fff; text-transform: uppercase; letter-spacing: 0.6px; background: #1a1a2e; padding: 6px 9px; margin-top: 12px; margin-bottom: 8px; }

  /* INFO TABLE */
  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td { padding: 4px 8px; font-size: 9pt; border-bottom: 1px solid #f1f5f9; vertical-align: middle; white-space: nowrap; }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 16%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 17%; color: #1a1a2e; font-weight: 400; }

  /* STATS */
  .stats-table { width: 100%; border-collapse: collapse; margin-bottom: 12px; }
  .stats-table td { border: 1px solid #e5e7eb; padding: 5px 8px; text-align: center; }
  .s-label { font-size: 6.5pt; color: #9ca3af; display: block; text-transform: uppercase; letter-spacing: 0.4px; }
  .s-value { font-size: 11pt; font-weight: 700; color: #1a1a2e; display: block; margin-top: 2px; }

  /* CALENDAR TABLE */
  .cal-table { width: 100%; border-collapse: collapse; table-layout: fixed; }
  .cal-table thead tr { background: #1a1a2e; color: #fff; }
  .cal-table thead th { padding: 5px 6px; font-size: 7pt; font-weight: 700; text-align: left; border: 1px solid #374151; text-transform: uppercase; letter-spacing: 0.3px; }
  .cal-table thead th.staff-col { width: 14%; }
  .cal-table tbody td { padding: 4px 5px; font-size: 8pt; border: 1px solid #e5e7eb; vertical-align: top; }
  .cal-table tbody td.staff-col { background: #f9fafb; }
  .cal-table tbody td.staff-col .s-name { font-weight: 700; color: #1a1a2e; }
  .cal-table tbody td.staff-col .s-role { font-size: 6.5pt; color: #9ca3af; margin-top: 1px; }
  .cal-table tbody tr:nth-child(even) td:not(.staff-col) { background: #fcfcfd; }

  /* SHIFT PILLS */
  .shift-pill { border-radius: 4px; padding: 3px 5px; font-weight: 700; font-size: 7.5pt; display: block; }
  .shift-pill .s-time { font-weight: 400; font-size: 6.5pt; opacity: 0.8; display: block; margin-top: 1px; }
  .morning   { background: #dbeafe; color: #1e40af; }
  .afternoon { background: #fef3c7; color: #92400e; }
  .night     { background: #e0e7ff; color: #3730a3; }
  .day       { background: #f3f4f6; color: #374151; }
  .off-pill  { color: #9ca3af; font-size: 7.5pt; text-align: center; padding: 3px 0; display: block; }

  /* FOOTER */
  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 16px 0 10px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 14px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Shift List</div>
        <div class="doc-subtitle">Staff Shift Calendar</div>
        <div class="doc-ref">
          <strong>Week:</strong> {{ filters.week_start }} &ndash; {{ filters.week_end }}<br>
          <strong>Generated:</strong> {{ generated_at }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- STATUS PILLS -->
  <div class="pills-row">
    <span class="pill">{{ filters.department }}</span>
    <span class="pill">{{ filters.shift_type }}</span>
  </div>

  <!-- FILTERS -->
  <div class="section-title">Report Filters</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:16%" /><col style="width:17%" />
      <col style="width:16%" /><col style="width:17%" />
      <col style="width:16%" /><col style="width:17%" />
    </colgroup>
    <tr>
      <td class="info-key">Department</td><td class="info-val">{{ filters.department }}</td>
      <td class="info-key">Shift Type</td><td class="info-val">{{ filters.shift_type }}</td>
      <td class="info-key">Week</td><td class="info-val">{{ filters.week_start }} &ndash; {{ filters.week_end }}</td>
    </tr>
  </table>

  <!-- STATS -->
  {% if stats %}
  <div class="section-title">Summary</div>
  <table class="stats-table" cellpadding="0" cellspacing="0">
    <tr>
      <td><span class="s-label">Total Staff</span><span class="s-value">{{ stats.total_staff or 0 }}</span></td>
      <td><span class="s-label">Assigned</span><span class="s-value">{{ stats.assigned or 0 }}</span></td>
      <td><span class="s-label">Unassigned</span><span class="s-value">{{ stats.unassigned or 0 }}</span></td>
      <td><span class="s-label">Morning</span><span class="s-value">{{ stats.morning or 0 }}</span></td>
      <td><span class="s-label">Afternoon</span><span class="s-value">{{ stats.afternoon or 0 }}</span></td>
      <td><span class="s-label">Night</span><span class="s-value">{{ stats.night or 0 }}</span></td>
      <td><span class="s-label">Days Off</span><span class="s-value">{{ stats.off or 0 }}</span></td>
    </tr>
  </table>
  {% endif %}

  <!-- CALENDAR -->
  <div class="section-title">Shift Calendar &mdash; {{ staff | length }} staff member(s)</div>
  {% if staff and staff | length %}
  <table class="cal-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th class="staff-col">Staff / Role</th>
        {% for day in days %}
        <th>{{ day.label }}<br>{{ day.dateLabel }}</th>
        {% endfor %}
      </tr>
    </thead>
    <tbody>
      {% for member in staff %}
      <tr>
        <td class="staff-col">
          <div class="s-name">{{ member.name }}</div>
          <div class="s-role">{{ member.role }}</div>
        </td>
        {% for day in days %}
        {% set shift = member.shifts.get(day.date) if member.shifts else None %}
        <td>
          {% if shift %}
          {% set sl = (shift.shift or '') | lower %}
          <div class="shift-pill {% if 'morning' in sl %}morning{% elif 'afternoon' in sl or 'evening' in sl %}afternoon{% elif 'night' in sl %}night{% else %}day{% endif %}">
            {{ shift.shift }}
            {% if shift.time %}<span class="s-time">{{ shift.time }}</span>{% endif %}
          </div>
          {% else %}
          <div class="off-pill">OFF</div>
          {% endif %}
        </td>
        {% endfor %}
      </tr>
      {% endfor %}
    </tbody>
  </table>
  {% else %}
  <p style="padding:16px;text-align:center;color:#9ca3af;font-size:8.5pt;border:1px dashed #e5e7eb;">No active staff found for the selected filters.</p>
  {% endif %}


  <!-- LEGEND -->
  <div style="margin-top:8px;font-size:7.5pt;color:#6b7280;">
    {% if shift_types %}
      {% for st in shift_types %}
        {% set sl = st | lower %}
        <span style="margin-right:10px;">
          <span style="display:inline-block;width:9px;height:9px;border-radius:2px;margin-right:3px;vertical-align:middle;
            background:{% if 'morning' in sl %}#dbeafe{% elif 'afternoon' in sl or 'evening' in sl %}#fef3c7{% elif 'night' in sl %}#e0e7ff{% else %}#f3f4f6{% endif %};
          "></span>{{ st }}
        </span>
      {% endfor %}
      <span style="margin-right:10px;"><span style="display:inline-block;width:9px;height:9px;border-radius:2px;margin-right:3px;vertical-align:middle;background:#9ca3af;"></span>OFF</span>
    {% else %}
      <span style="color:#9ca3af;">No shift types configured in system.</span>
    {% endif %}
  </div>

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This report is generated by the {{ company }} Property Management System.<br>
          For internal use only &mdash; Staff Roaster Module
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
